import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';
import { SiteviewService } from '../../../core/services/siteview.service';
import { MilestoneStatus } from '../../../core/models/siteview.models';

@Component({
  selector: 'app-milestones',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './milestones.component.html',
  styleUrl: './milestones.component.css',
})
export class MilestonesComponent {
  private readonly projectId = this.route.parent?.snapshot.paramMap.get('id') ?? '';
  private readonly refresh = signal(0);

  readonly statuses: MilestoneStatus[] = ['pending', 'in_progress', 'at_risk', 'done'];
  readonly milestones = computed(() => {
    this.refresh();
    return this.sv.milestonesForProject(this.projectId);
  });

  showAdd = false;
  draft = { name: '', dueOn: '', status: 'pending' as MilestoneStatus };

  constructor(
    public auth: AuthService,
    private sv: SiteviewService,
    private route: ActivatedRoute,
  ) {}

  statusLabel(s: MilestoneStatus): string {
    return { pending: 'Pending', in_progress: 'In progress', at_risk: 'At risk', done: 'Done' }[s];
  }
  statusBadge(s: MilestoneStatus): string {
    return {
      pending: 'badge-muted',
      in_progress: 'badge-info',
      at_risk: 'badge-danger',
      done: 'badge-success',
    }[s];
  }

  changeStatus(id: string, status: MilestoneStatus): void {
    this.sv.setMilestoneStatus(id, status);
    this.refresh.update((n) => n + 1);
  }

  add(): void {
    if (!this.draft.name.trim() || !this.draft.dueOn) return;
    this.sv.createMilestone({
      projectId: this.projectId,
      name: this.draft.name.trim(),
      dueOn: this.draft.dueOn,
      status: this.draft.status,
    });
    this.draft = { name: '', dueOn: '', status: 'pending' };
    this.showAdd = false;
    this.refresh.update((n) => n + 1);
  }
}
